head.b:skin:
:root{
  /* ===== 주제 포인트 컬러 (블로그별로 이 블록만 교체) — 현재: 건강(차분한 세이지 그린) ===== */
  --accent:#4f6b47;
  --accent-weak:#e7ede0;
  --accent-ink:#3c5334;

  /* ===== 공통 디자인 토큰 (따뜻한 오프화이트/크림 톤) ===== */
  --bg:#faf9f6;
  --surface:#fffcf7;
  --surface-2:#f2efe7;
  --ink:#2b2a27;
  --ink-2:#6f6a5e;
  --line:#e7e2d6;
  --radius:16px;
  --shadow:0 1px 2px rgba(40,35,26,.05), 0 8px 24px rgba(40,35,26,.07);
  --shadow-hover:0 2px 4px rgba(40,35,26,.08), 0 16px 40px rgba(40,35,26,.14);
  --maxw:1120px;
  --font:"Pretendard","Pretendard Variable",-apple-system,BlinkMacSystemFont,"Apple SD Gothic Neo","Segoe UI",Roboto,"Noto Sans KR",sans-serif;
}
@media (prefers-color-scheme:dark){
  :root{
    --bg:#1b1917; --surface:#242220; --surface-2:#2a2723;
    --ink:#ece7dd; --ink-2:#b0a99b; --line:#3a352e;
    --accent:#7fa06e; --accent-weak:#28331f; --accent-ink:#9cba8a;
    --shadow:0 1px 2px rgba(0,0,0,.3),0 8px 24px rgba(0,0,0,.35);
    --shadow-hover:0 2px 4px rgba(0,0,0,.4),0 16px 40px rgba(0,0,0,.5);
  }
}
*{box-sizing:border-box}
html{-webkit-text-size-adjust:100%}
body{
  margin:0;background:var(--bg);color:var(--ink);
  font-family:var(--font);line-height:1.75;font-size:16px;
  -webkit-font-smoothing:antialiased;
}
a{color:inherit;text-decoration:none}
img{max-width:100%;display:block}
.wrap{max-width:var(--maxw);margin:0 auto;padding:0 28px}

/* ===== Header ===== */
.site-header{
  position:sticky;top:0;z-index:50;
  background:color-mix(in srgb,var(--bg) 88%,transparent);
  backdrop-filter:saturate(160%) blur(12px);
  border-bottom:1px solid var(--line);
}
.header-inner{display:flex;align-items:center;gap:16px;height:64px}
.brand{display:flex;align-items:center;gap:10px;font-weight:800;font-size:19px;letter-spacing:-.02em;flex:none;white-space:nowrap}
.brand .dot{width:26px;height:26px;border-radius:8px;background:var(--accent);
  display:grid;place-items:center;color:#fff;font-size:14px;box-shadow:var(--shadow);flex:none}
/* 메뉴: 줄바꿈 없이 한 줄 유지, 넘치면 가로 스크롤(PC/모바일 공통 — 좁아지면 자연히 스크롤 탭이 됨) */
.nav{display:flex;align-items:center;gap:2px;margin-left:auto;flex-wrap:nowrap;
  overflow-x:auto;overflow-y:hidden;-webkit-overflow-scrolling:touch;
  scrollbar-width:none;-ms-overflow-style:none}
.nav::-webkit-scrollbar{display:none}
.nav ul{list-style:none;display:flex;gap:2px;flex-wrap:nowrap;margin:0;padding:0}
.nav a{display:inline-flex;align-items:center;padding:0 14px;height:33px;border-radius:999px;color:var(--ink-2);font-weight:600;font-size:14.5px;transition:.18s;white-space:nowrap;flex:none}
.nav a:hover{color:var(--accent-ink);background:var(--accent-weak)}
.nav a.active{color:#fff;background:var(--accent)}

/* ===== Hero / category strip ===== */
.hero{padding:44px 0 20px}
.hero h1{font-size:30px;line-height:1.3;letter-spacing:-.03em;margin:0 0 10px;font-weight:800}
.hero p{color:var(--ink-2);margin:0;font-size:16.5px}
.chips{display:flex;gap:8px;flex-wrap:wrap;margin-top:20px}
.chip{display:inline-block;padding:7px 14px;border:1px solid var(--line);border-radius:999px;font-size:13.5px;font-weight:600;color:var(--ink-2);transition:.18s}
.chip:hover{border-color:var(--accent);color:var(--accent-ink)}

/* ===== Layout ===== */
.layout{display:grid;grid-template-columns:1fr 300px;gap:36px;padding:28px 0 60px}
@media(max-width:900px){.layout{grid-template-columns:1fr}}

/* ===== Card grid ===== */
.section-title{display:flex;align-items:center;gap:10px;margin:0 0 18px;font-size:15px;font-weight:800;letter-spacing:.02em;text-transform:uppercase;color:var(--ink-2)}
.section-title::before{content:"";width:4px;height:16px;border-radius:2px;background:var(--accent)}
.cards{display:flex;flex-direction:column;gap:12px}
/* 최신 글은 모든 화면 폭에서 2개까지만 노출, 3번째 카드부터 숨김 */
.cards>.card:nth-child(n+3){display:none}
.card{
  background:var(--surface);border:1px solid var(--line);border-radius:var(--radius);
  overflow:hidden;box-shadow:var(--shadow);transition:transform .2s,box-shadow .2s,border-color .2s;
  display:flex;flex-direction:row;align-items:stretch;
}
.card:hover{transform:translateY(-4px);box-shadow:var(--shadow-hover);border-color:color-mix(in srgb,var(--accent) 40%,var(--line))}
.card .thumb{width:200px;flex:none;aspect-ratio:auto;background:
  linear-gradient(135deg,var(--accent-weak),color-mix(in srgb,var(--accent) 22%,transparent));
  position:relative;display:block}
.card .thumb img{width:100%;height:100%;object-fit:cover}
.card .thumb .tag{position:absolute;left:12px;top:12px;background:var(--surface);color:var(--accent-ink);
  font-size:12px;font-weight:700;padding:4px 10px;border-radius:999px;box-shadow:var(--shadow)}
.card .body{padding:16px 16px 18px;flex:1;min-width:0;display:flex;flex-direction:column;justify-content:center}
.card h3{margin:0 0 8px;font-size:17px;line-height:1.4;letter-spacing:-.02em;font-weight:700}
.card h3 a{display:block}
.card:hover h3{color:var(--accent-ink)}
.card p{margin:0;color:var(--ink-2);font-size:14px;line-height:1.6;
  display:-webkit-box;-webkit-line-clamp:2;-webkit-box-orient:vertical;overflow:hidden}
.card .meta{margin-top:14px;display:flex;gap:10px;align-items:center;color:var(--ink-2);font-size:12.5px}
.card .meta .d{width:3px;height:3px;border-radius:50%;background:var(--ink-2)}
@media(max-width:620px){
  .cards{gap:10px}
  .card .thumb{width:104px;aspect-ratio:auto}
  .card .thumb .tag{display:none}
  .card .body{padding:10px 12px}
  .card h3{font-size:14.5px;margin:0 0 4px}
  .card p{font-size:12.5px;-webkit-line-clamp:1}
  .card .meta{margin-top:6px;font-size:11px}
}

/* ===== Ad slot ===== */
.ad{margin:24px 0;border:1px dashed color-mix(in srgb,var(--accent) 45%,var(--line));
  border-radius:14px;background:var(--surface-2);color:var(--ink-2);
  text-align:center;padding:22px;font-size:13px;font-weight:600;letter-spacing:.03em}

/* ===== BlogSearch 위젯(Blogger 기본 검색창) 스타일 보정 — 얇은 기본 input을 테마 톤에 맞는 검색창으로 ===== */
.widget.BlogSearch{margin:8px 0 24px}
.widget.BlogSearch h2.title{font-size:15px;font-weight:800;letter-spacing:.02em;color:var(--ink-2);margin:0 0 10px}
.widget.BlogSearch table.gsc-search-box{width:100%;border-collapse:collapse}
.widget.BlogSearch td.gsc-input{width:100%}
.widget.BlogSearch input.gsc-input{
  box-sizing:border-box;width:100%;height:46px;padding:0 16px;
  border:1px solid var(--line);border-radius:999px;
  background:var(--surface);color:var(--ink);
  font-family:var(--font);font-size:14.5px;
}
.widget.BlogSearch input.gsc-input:focus{outline:none;border-color:var(--accent)}
.widget.BlogSearch td.gsc-search-button{padding-left:8px}
.widget.BlogSearch input.gsc-search-button{
  height:46px;padding:0 22px;border:none;border-radius:999px;
  background:var(--accent);color:#fff;
  font-family:var(--font);font-size:14.5px;font-weight:700;
  white-space:nowrap;cursor:pointer;transition:.18s;
}
.widget.BlogSearch input.gsc-search-button:hover{background:var(--accent-ink)}

/* ===== Sidebar ===== */
.side .box{background:var(--surface);border:1px solid var(--line);border-radius:var(--radius);
  padding:18px;box-shadow:var(--shadow);margin-bottom:20px}
.side h4{margin:0 0 14px;font-size:14px;font-weight:800;letter-spacing:.02em}
.side .pop-list{counter-reset:pop}
.side .pop{counter-increment:pop;display:flex;gap:12px;padding:9px 0;border-bottom:1px solid var(--line)}
.side .pop:last-child{border-bottom:0}
.side .pop .n{color:var(--accent);font-weight:800;font-size:15px;min-width:18px}
.side .pop .n::before{content:counter(pop)}
.side .pop a{font-size:14px;font-weight:600;line-height:1.45}
.side .pop a:hover{color:var(--accent-ink)}
.side .labels{display:flex;flex-wrap:wrap;gap:8px}
.side .labels a{display:inline-block;font-size:13px;font-weight:600;padding:6px 12px;border-radius:999px;background:var(--surface-2);color:var(--ink-2);transition:.18s}
.side .labels a:hover{background:var(--accent-weak);color:var(--accent-ink)}

/* ===== Article (post/page) ===== */
.article{background:var(--surface);border:1px solid var(--line);border-radius:var(--radius);
  padding:30px;box-shadow:var(--shadow);margin-top:0}
.article h2{font-size:24px;letter-spacing:-.02em;margin:.2em 0 .5em}
.article h3{font-size:18px;margin:1.4em 0 .5em}
.article p{color:var(--ink);margin:0 0 1em}
.article b,.article strong{color:var(--accent-ink);background:var(--accent-weak);padding:0 3px;border-radius:4px}
.article img{border-radius:12px;margin:1em 0}
.post-meta{color:var(--ink-2);font-size:13px;margin:0 0 18px;display:flex;gap:10px;flex-wrap:wrap}
.post-meta a{color:var(--ink-2)}
.post-meta a:hover{color:var(--accent-ink)}
.blog-pager{display:flex;justify-content:space-between;gap:12px;margin-top:24px;flex-wrap:wrap}
.blog-pager a{padding:10px 16px;border:1px solid var(--line);border-radius:999px;font-size:14px;font-weight:600;color:var(--ink-2)}
.blog-pager a:hover{border-color:var(--accent);color:var(--accent-ink)}
.comments{margin-top:32px}

/* ===== Footer ===== */
.site-footer{border-top:1px solid var(--line);background:var(--surface-2);margin-top:20px;padding:36px 0}
.foot-inner{display:flex;flex-wrap:wrap;gap:16px 28px;align-items:center}
.foot-links{display:flex;flex-wrap:wrap;gap:8px 20px;list-style:none;margin:0;padding:0}
.foot-links a{color:var(--ink-2);font-size:14px;font-weight:600}
.foot-links a:hover{color:var(--accent-ink)}
.foot-copy{color:var(--ink-2);font-size:13px}
.badge{font-size:11px;color:var(--ink-2);border:1px solid var(--line);border-radius:999px;padding:3px 9px;margin-left:auto}
/* ===== 세부정보(Attribution)/신고하기(ReportAbuse) — 페이지 맨 아래 별도 영역으로 이동 ===== */
.foot-meta{border-top:1px solid var(--line);margin-top:16px;padding-top:16px;
  display:flex;justify-content:center;align-items:center;gap:18px;flex-wrap:wrap}
.foot-meta .foot-attribution{margin:0;font-size:12px;color:var(--ink-2)}
.foot-meta .foot-attribution a{color:var(--ink-2)}
.foot-meta .foot-attribution a:hover{color:var(--accent-ink)}
.foot-meta .foot-report{margin:0;font-size:12px;font-weight:600}
.foot-meta .foot-report a{color:var(--ink-2)}
.foot-meta .foot-report a:hover{color:var(--accent-ink)}

/* ===== Responsive breakpoints (모바일 우선 보정, 320px 이하까지 안전) ===== */
@media(max-width:480px){
  .wrap{padding:0 20px}
  .nav a{padding:0 12px;font-size:14px}
  .hero{padding:28px 0 14px}
  .hero h1{font-size:23px}
  .hero p{font-size:14.5px}
  .layout{gap:24px;padding:20px 0 40px}
  .article{padding:20px}
  .article h2{font-size:20px}
  .foot-inner{gap:12px 18px}
  .foot-copy{margin-left:0}
  .blog-pager a{flex:1 1 auto;text-align:center}
}
